<template><div class="card p-3"><div class="flex flex-wrap gap-3 items-center justify-between"><div><h1 class="text-xl font-bold">Units Housing</h1><p class="text-xs text-slate-400">Home > Rooms</p></div><div class="flex gap-2 items-center"><input v-model="searchLocal" @input="$emit('update:search',searchLocal)" class="input w-72" placeholder="Search by room number / Room ID"><input type="date" v-model="dateLocal" @input="$emit('update:date',dateLocal)" class="input"><div class="text-green-600 text-xs font-semibold">Today {{ dateLocal }}</div></div></div></div></template>
<script setup>import {ref,watch} from 'vue'; const props=defineProps({search:String,date:String}); const searchLocal=ref(props.search); const dateLocal=ref(props.date); watch(()=>props.search,v=>searchLocal.value=v); watch(()=>props.date,v=>dateLocal.value=v);</script>
